import{_ as t,c as o,o as n,ag as i}from"./chunks/framework.S-Qvb3wi.js";const m=JSON.parse('{"title":"Circulation Mechanism: Closed-Loop Value Cycle","description":"","frontmatter":{},"headers":[],"relativePath":"Circulation-Mechanism.md","filePath":"Circulation-Mechanism.md"}'),a={name:"Circulation-Mechanism.md"};function s(r,e,l,c,d,u){return n(),o("div",null,e[0]||(e[0]=[i('<h1 id="circulation-mechanism-closed-loop-value-cycle" tabindex="-1">Circulation Mechanism: Closed-Loop Value Cycle <a class="header-anchor" href="#circulation-mechanism-closed-loop-value-cycle" aria-label="Permalink to &quot;Circulation Mechanism: Closed-Loop Value Cycle&quot;">​</a></h1><p>$DGAI operates within a closed-loop economic system, ensuring transparent value flow among users, node operators, and the broader ecosystem. This mechanism is governed by smart contracts (e.g., Bill Contract) and enforced via DGrid Nodes, eliminating intermediaries and aligning incentive mechanisms with network health.</p><h2 id="core-cycle-from-payment-to-rewards" tabindex="-1">Core Cycle: From Payment to Rewards <a class="header-anchor" href="#core-cycle-from-payment-to-rewards" aria-label="Permalink to &quot;Core Cycle: From Payment to Rewards&quot;">​</a></h2><p>The circulation of $DGAI follows a structured process that links users’ inference demands to node contributions:</p><ol><li><strong>Initiation of User Payment</strong> When a user submits an inference request via the user client, the process unfolds as follows:</li></ol><ul><li>The request is routed to a DGrid Node, which calculates the task fee using the following formula: <code>Cost = Compute Unit (CU) × Base Price × (1 + Latency Penalty Coefficient)</code></li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><ul><li><strong>Compute Unit (CU)</strong>: A standardized metric for measuring inference complexity (correlated with model size, number of input tokens, and execution time).</li><li><strong>Base Price</strong>: A fixed price per CU (adjustable via governance mechanisms, with an initial value of 0.05 $DGAI).</li><li><strong>Latency Penalty Coefficient</strong>: Ranges from 0 to 0.3 (fine-tuned for latency exceeding the target threshold).</li></ul></div><ul><li>The user’s $DGAI is escrowed via the <strong>Bill Contract</strong>—a smart contract deployed on the blockchain—to ensure payment upon task completion.</li></ul><ol start="2"><li><strong>Distribution of Node Rewards</strong> After inference is completed (verified by Grid Nodes and archived in the AI DA Layer), the escrowed $DGAI is distributed via the Bill Contract.</li></ol><p>Recipients include:</p><ul><li><strong>DGrid Nodes</strong>: Compensation for executing inference tasks (proportional to CU, latency, and uptime).</li><li><strong>Treasury</strong>: Used for network maintenance (e.g., AI DA Layer fees, security audits) and developer grants.</li><li><strong>Governance Pool</strong>: Incentivizes $DGAI holders to participate in voting (e.g., protocol upgrades, parameter adjustments).</li></ul><ol start="3"><li><strong>Staking and Lock-Up Requirements</strong> Nodes participating in the network must lock up $DGAI as collateral to ensure accountability.</li><li><strong>Governance and Fee Allocation</strong></li></ol><ul><li><strong>Governance Pool</strong>: 5% of task payments (plus 10% of annual treasury funds) are distributed to $DGAI holders who participate in proposal voting (e.g., adjusting base prices, whitelisting new models).</li><li><strong>Network Fees</strong>: A 2% processing fee is deducted upfront from all task payments to cover smart contract gas costs and AI DA Layer archiving, ensuring transaction efficiency.</li></ul><ol start="5"><li><strong>Penalty Mechanisms and Token Burning</strong> Node violations trigger automatic penalties to protect network integrity:</li></ol><ul><li><strong>Confiscated Tokens</strong>: 5–20% of a node’s staked $DGAI will be confiscated for malicious behaviors (e.g., submitting false inference results, downtime exceeding 72 hours).</li><li><strong>Burning Mechanism</strong>: All confiscated tokens are permanently burned, reducing the total supply of $DGAI over time and enhancing scarcity.</li></ul><h2 id="key-processes-capital-inflows-and-outflows" tabindex="-1">Key Processes: Capital Inflows and Outflows <a class="header-anchor" href="#key-processes-capital-inflows-and-outflows" aria-label="Permalink to &quot;Key Processes: Capital Inflows and Outflows&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Inflows (Sources of $DGAI)</th><th>Outflows (Uses of $DGAI)</th></tr></thead><tbody><tr><td>Fees paid by users for inference tasks</td><td>Rewards for node operators for inference tasks</td></tr><tr><td>Weekly rewards for DGrid Nodes</td><td>Staking lock-up for node participation</td></tr><tr><td>Governance rewards for voting participants</td><td>Network fees (gas, AI DA Layer archiving)</td></tr><tr><td>Initial distribution (e.g., public sale, airdrops)</td><td>Confiscated tokens (burned)</td></tr></tbody></table><p>This mechanism ensures $DGAI maintains utility as both a medium of exchange and a governance tool, fostering a self-sustaining ecosystem where value is proportional to network participation. By linking payments to contributions and enforcing accountability through staking mechanisms, the circulation of $DGAI reinforces the decentralization and resilience of DGrid AI.</p>',18)]))}const f=t(a,[["render",s]]);export{m as __pageData,f as default};
